Example
#include <iostream>
using namespace std;
int main() {
int j = 1;
// pi is an int pointer initialized to the address of j
int* pi = &j;
int*& ref = pi; // ref is a reference variable of type int*
cout << "j = " << j << ", ";
cout << "*pi = " << *pi << ", *ref = " << *ref << endl;
int k = 2;
pi = &k;
cout << "j = " << j << ", ";
cout << "*pi = " << *pi << ", *ref = " << *ref << endl;
return 0;
}
Output:
j = 1, *pi = 1, *ref = 1
j = 1, *pi = 2, *ref = 2
